SELECT COUNT(*)
FROM hm_query.product_catalog_flat p
WHERE p.seller_id = #{supplierId}
AND p.product_status = #{stateId}
AND p.stock_status = #{stockStatus}
AND (p.product_name ILIKE CONCAT('%', #{q}, '%') OR p.primary_sku ILIKE CONCAT('%', #{q}, '%') OR p.brand ILIKE CONCAT('%', #{q}, '%'))

SELECT COUNT(*)
FROM hm_query.inventory_health_flat inv
JOIN hm_query.product_catalog_flat p ON inv.product_id = p.product_id
WHERE p.seller_id = #{supplierId}
AND inv.stock_status = #{stockStatus}
AND (inv.product_name ILIKE CONCAT('%', #{q}, '%') OR inv.sku ILIKE CONCAT('%', #{q}, '%'))

SELECT COUNT(*)
FROM hm_query.return_detail_flat rr
JOIN hm_query.order_details_flat o ON rr.order_id = o.order_id
WHERE o.seller_id = #{supplierId}
AND rr.return_status = #{stateId}
AND (rr.product_name ILIKE CONCAT('%', #{q}, '%') OR rr.reason ILIKE CONCAT('%', #{q}, '%'))

SELECT COUNT(*)
FROM hm_query.fulfillment_flat ff
JOIN hm_query.order_details_flat o ON ff.order_id = o.order_id
WHERE o.seller_id = #{supplierId}
AND ff.fulfillment_status = #{stateId}
AND (ff.tracking_number ILIKE CONCAT('%', #{q}, '%') OR ff.fulfillment_id ILIKE CONCAT('%', #{q}, '%') OR ff.warehouse_name ILIKE CONCAT('%', #{q}, '%'))
